t.script:
(function() {
    var liffId = '';
    var target = '';

    // 直接跳轉對照表（fallback）
    var DIRECT_URLS = {
        'book': '/appointment/1/schedule',
        'my-bookings': '/my/ext-bookings',
        'profile': '/my/account'
    };

    function setStatus(text) {
        var el = document.getElementById('liff-status-text');
        if (el) el.textContent = text;
    }

    function postToken(idToken) {
        var form = document.createElement('form');
        form.method = 'POST';
        form.action = window.location.pathname;
        var input = document.createElement('input');
        input.type = 'hidden';
        input.name = 'id_token';
        input.value = idToken;
        form.appendChild(input);
        document.body.appendChild(form);
        form.submit();
    }

    function fallback() {
        // 無法取得 token，直接跳轉目標頁面
        var url = DIRECT_URLS[target] || '/appointment/1/schedule';
        setStatus('正在跳轉...');
        window.location.href = url;
    }

    if (!liffId) {
        setStatus('設定錯誤');
        return;
    }

    if (typeof liff === 'undefined') {
        setStatus('SDK 載入失敗');
        fallback();
        return;
    }

    liff.init({ liffId: liffId }).then(function() {
        console.log('[Bridge] init OK, loggedIn=' + liff.isLoggedIn());

        if (!liff.isLoggedIn()) {
            // 未登入 → 不呼叫 liff.login()，直接 fallback
            setStatus('正在跳轉...');
            fallback();
            return;
        }

        // 取得 ID Token
        var idToken = null;
        try {
            idToken = liff.getIDToken();
        } catch(e) {
            console.warn('[Bridge] getIDToken error', e);
        }

        if (idToken) {
            setStatus('登入成功，跳轉中...');
            postToken(idToken);
        } else {
            // 有登入但無 token（可能 scope 缺 openid）
            setStatus('正在跳轉...');
            fallback();
        }
    }).catch(function(err) {
        console.error('[Bridge] init failed', err);
        setStatus('正在跳轉...');
        fallback();
    });
})();
